diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 394dfca262e1..7b7d13021931 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -3012,6 +3012,40 @@ struct DecomposedSelect {
 };
 } // namespace

+/// Look for patterns like
+///   %sel1 = select i1 %c1, i32 %a, i32 %b
+///   %sel2 = select i1 %c1, i32 %b, i32 %a
+///   %ret = select i1 %c2, i32 %sel1, i32 %sel2
+/// and rewrite it as
+///   %xor = xor i1 %c1, %c2
+///   %ret = select i1 %xor, i32 %b, i32 %a
+static Instruction *foldSelectOfSymmetricSelects(SelectInst &SI,
+                                                  InstCombiner::BuilderTy &Builder) {
+  Value *TrueVal = SI.getTrueValue();
+  Value *FalseVal = SI.getFalseValue();
+
+  // Both true and false values must be selects
+  SelectInst *Sel1 = dyn_cast<SelectInst>(TrueVal);
+  SelectInst *Sel2 = dyn_cast<SelectInst>(FalseVal);
+  if (!Sel1 || !Sel2)
+    return nullptr;
+
+  // The two inner selects must have the same condition
+  if (Sel1->getCondition() != Sel2->getCondition())
+    return nullptr;
+
+  // The inner selects must have swapped true/false values
+  if (Sel1->getTrueValue() != Sel2->getFalseValue() ||
+      Sel1->getFalseValue() != Sel2->getTrueValue())
+    return nullptr;
+
+  // Create XOR of conditions
+  Value *XorCond = Builder.CreateXor(SI.getCondition(), Sel1->getCondition());
+
+  // Create the optimized select: select (c1 xor c2), false_val, true_val
+  return SelectInst::Create(XorCond, Sel1->getFalseValue(), Sel1->getTrueValue());
+}
+
 /// Look for patterns like
 ///   %outer.cond = select i1 %inner.cond, i1 %alt.cond, i1 false
 ///   %inner.sel = select i1 %inner.cond, i8 %inner.sel.t, i8 %inner.sel.f
@@ -3987,6 +4021,9 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
     }
   }

+  if (Instruction *I = foldSelectOfSymmetricSelects(SI, Builder))
+    return I;
+
   if (Instruction *I = foldNestedSelects(SI, Builder))
     return I;

